23→export type ListItemMetadataEntry =
24→  | {
25→      type: 'label';
26→      title: string;
27→      text?: string;
28→    }
29→  | {
30→      type: 'link';
31→      title: string;
32→      text: string;
33→      target: string;
34→    }
35→  | {
36→      type: 'tag-list';
37→      title: string;
38→      tags: {
