 91→export function App() {
 92→  const [query, setQuery] = useState('');
 93→  const [selectedIndex, setSelectedIndex] = useState(0);
 94→
 95→  const filtered = useMemo(() => filterSections(MOCK_SECTIONS, query), [query]);
 96→  const allItems = useMemo(() => flattenItems(filtered), [filtered]);
 97→  const selectedItem = allItems[selectedIndex];
 98→
 99→  const handleActiveIndexChange = useCallback((index: number) => {
100→    setSelectedIndex(index);
101→  }, []);
102→
103→  const detail = selectedItem?.detail;
104→
105→  return (
106→    <CommandPalette>
107→      <SearchBar value={query} onChange={setQuery} />
108→      <div className="command-palette__body">
109→        <div className="command-palette__list-container">
110→          {allItems.length === 0 ? (
111→            <EmptyState
112→              icon={<SearchIcon />}
113→              title="No Results"
114→              description="Try a different search term"
115→            />
116→          ) : (
117→            <List
118→              itemCount={allItems.length}
119→              onActiveIndexChange={handleActiveIndexChange}
120→            >
121→              {(() => {
122→                let globalIndex = 0;
123→                return filtered.map(section => (
124→                  <ListSection key={section.title} title={section.title}>
125→                    {section.items.map(item => {
126→                      const idx = globalIndex++;
127→                      return (
128→                        <ListItem
129→                          key={item.id}
130→                          index={idx}
131→                          title={item.title}
132→                          subtitle={item.subtitle}
133→                          icon={item.icon}
134→                          accessories={item.accessories}
135→                        />
136→                      );
137→                    })}
138→                  </ListSection>
139→                ));
140→              })()}
141→            </List>
142→          )}
143→        </div>
144→        {detail && (
145→          <Detail
146→            markdown={detail.markdown}
147→            metadata={
148→              detail.metadata ? (
149→                <DetailMetadata>
150→                  {detail.metadata.map(renderMetadataEntry)}
151→                </DetailMetadata>
152→              ) : undefined
153→            }
154→          />
155→        )}
156→      </div>
157→      <ActionPanel
158→        actions={[
159→          {
160→            label: 'Open',
161→            shortcut: <Kbd keys={['↵']} />,
162→          },
163→          {
164→            label: 'Actions',
165→            shortcut: (
166→              <Kbd
167→                keys={[
168→                  '⌘',
169→                  'K',
170→                ]}
171→              />
172→            ),
173→          },
174→        ]}
175→      />
176→    </CommandPalette>
177→  );
178→}
