 98→export interface DetailMetadataProps {
 99→  children: ReactNode;
100→}
101→
102→interface DetailMetadataComponent {
103→  (props: DetailMetadataProps): ReactNode;
104→  Label: typeof MetadataLabel;
105→  Link: typeof MetadataLink;
106→  TagList: typeof MetadataTagList;
107→  Tag: typeof MetadataTag;
108→  Separator: typeof MetadataSeparator;
