111→export const DetailMetadata: DetailMetadataComponent = Object.assign(
112→  function DetailMetadata({ children }: DetailMetadataProps) {
113→    return <div className="detail-metadata">{children}</div>;
114→  },
115→  {
116→    Label: MetadataLabel,
117→    Link: MetadataLink,
118→    TagList: MetadataTagList,
119→    Tag: MetadataTag,
120→    Separator: MetadataSeparator,
121→  },
